changeSet.sql:
IF EXISTS (
    SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_NAME = 'analyse_financiere' AND COLUMN_NAME = 'TOTAL_ACTIF'
    AND IS_NULLABLE = 'NO'
)
BEGIN
    ALTER TABLE analyse_financiere ALTER COLUMN TOTAL_ACTIF  DECIMAL(19,4)    NULL;
    ALTER TABLE analyse_financiere ALTER COLUMN TOTAL_PASSIF DECIMAL(19,4)    NULL;
    ALTER TABLE analyse_financiere ALTER COLUMN TYPE_ANALYSE NVARCHAR(20)     NULL;
    ALTER TABLE analyse_financiere ALTER COLUMN AVIS_AGENT   NVARCHAR(20)     NULL;
    ALTER TABLE analyse_financiere ALTER COLUMN COMMENTAIRE  NVARCHAR(500)    NULL;
END
